-- 2026-06-04 - Trucker Path map screenshot for Business Review Slide 6
--
-- Fills the 's6-search' image slot on Slide 6 ("Digital Presence -
-- Visibility That Drives Volume & Inside Sales"), under the 'Local
-- Search Presence' card. Auto-renders on every truck stop's Business
-- Review via gallerySrc({slot: 's6-search'}) - no per-stop work.
--
-- File is ASCII-only on purpose (see prior vendor-logo bug from 2026-06-04).
-- Idempotent: ON CONFLICT (id) DO UPDATE - re-running with a newer
-- screenshot replaces in place.

BEGIN;

INSERT INTO public.deck_gallery (id, slot_key, label, category, vendor_id, data_url, notes, updated_at) VALUES
  ('g_slot_s6_search', 's6-search', 'Trucker Path map listing', 'hero', NULL, 'data:image/jpeg;base64,', 'Uploaded 2026-06-04 via add_tp_map.py - 29673 bytes source', now())
ON CONFLICT (id) DO UPDATE SET
  data_url   = EXCLUDED.data_url,
  label      = EXCLUDED.label,
  category   = EXCLUDED.category,
  slot_key   = EXCLUDED.slot_key,
  notes      = EXCLUDED.notes,
  updated_at = EXCLUDED.updated_at;

COMMIT;

